css:
.ps-swatch { display: inline-flex; align-items: center; gap: var(--pds-space-05); padding: 0.2em 0.5em; border-radius: var(--pds-radius-sm); font-size: 0.8125rem; }
.ps-swatch__dot { flex-shrink: 0; width: 10px; height: 10px; border-radius: 50%; background-color: var(--ps-brand-family-color, currentColor); }
.ps-swatch--department .ps-swatch__dot { background-color: var(--ps-brand-family-department-color, #0B5FFF); }
.ps-swatch--hardware .ps-swatch__dot { background-color: var(--ps-brand-family-hardware-color, #FF6B00); }
.ps-swatch--warehouse-club .ps-swatch__dot { background-color: var(--ps-brand-family-warehouse-club-color, #00875A); }
.ps-swatch--map-marker .ps-swatch__dot { width: 24px; height: 24px; }
.ps-swatch--map-marker .ps-swatch__label { position: absolute; clip: rect(0 0 0 0); clip-path: inset(50%); }
@media (forced-colors: active) { .ps-swatch__dot { background-color: LinkText; } }
